/**
 * Player progression / onboarding state. Tracks where a new player is in their
 * journey so we can:
 *   - show a one-tap "Play your first puzzle" CTA for brand-new players
 *   - keep hints free + no game-over for the first 3 puzzles
 *   - hide advanced features (custom builder, advanced replay, hard mode) until
 *     the player has won 5 puzzles OR explicitly opts in
 *   - prompt "want to try harder?" exactly once, after puzzle 3
 *
 * All state lives in localStorage. Defaults assume a brand-new player so an
 * existing player with no progression flag set will be re-onboarded — to
 * avoid that, we set `installed=1` the first time *any* prior state key is
 * read on boot (see `inheritExistingInstall`).
 *
 * Time complexity: every helper is O(1) — reads/writes a single localStorage
 * entry.
 */

const KEY = 'bilko_etch_progression_v1';

export interface ProgressionState {
  v: 1;
  /** Number of puzzles the player has WON (not started). */
  winCount: number;
  /** True once the player has dismissed or opted into anything that proves
   *  they're an existing user (helps inherit advanced toggle defaults). */
  installed: boolean;
  /** Has the player explicitly toggled "show advanced" on? */
  showAdvanced: boolean;
  /** Have we shown the post-puzzle-3 "try harder mode?" prompt yet? */
  promptedHarder: boolean;
  /** Has the player dismissed the post-puzzle-3 prompt without accepting? */
  declinedHarder: boolean;
  /** Has the player started the intro puzzle at least once? Used to decide
   *  whether to show the one-tap onboarding CTA vs the regular picker. */
  startedIntro: boolean;
  /** Has the player completed the intro? (controls graduation messaging) */
  completedIntro: boolean;
}

const initial: ProgressionState = {
  v: 1,
  winCount: 0,
  installed: false,
  showAdvanced: false,
  promptedHarder: false,
  declinedHarder: false,
  startedIntro: false,
  completedIntro: false,
};

function read(): ProgressionState {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return { ...initial };
    const j = JSON.parse(raw);
    if (j?.v !== 1) return { ...initial };
    return { ...initial, ...j };
  } catch { return { ...initial }; }
}

function write(s: ProgressionState) {
  try { localStorage.setItem(KEY, JSON.stringify(s)); } catch { /* private mode */ }
}

export function getProgression(): ProgressionState { return read(); }

export function setProgression(patch: Partial<ProgressionState>): ProgressionState {
  const next = { ...read(), ...patch };
  write(next);
  return next;
}

/** Mark a win — increments winCount. Returns the new state. */
export function noteWin(): ProgressionState {
  const s = read();
  s.winCount += 1;
  s.installed = true;
  write(s);
  return s;
}

/**
 * Heuristic: is this an existing player from a prior version (v0.4.x) who has
 * never seen the v0.5 progression model? We treat them as "installed" so the
 * onboarding CTA doesn't show.
 *
 * Inputs (any of these implies prior usage):
 *  - tutorial seen
 *  - any lifetime stats persisted
 *  - any best-times persisted
 *  - any achievement unlocked
 */
export function inheritExistingInstall(): void {
  const cur = read();
  if (cur.installed) return;
  let prior = false;
  try {
    if (localStorage.getItem('etch_seen_tutorial') === '1') prior = true;
    if (!prior && localStorage.getItem('bilko_etch_stats_v1')) prior = true;
    if (!prior && localStorage.getItem('bilko_etch_best_times_v1')) prior = true;
    if (!prior && localStorage.getItem('bilko_etch_achievements_v1')) prior = true;
  } catch { /* ignore */ }
  if (prior) {
    // Existing players get advanced surface ON by default (preserves their
    // expectations). The toggle is still in Settings if they want to hide it.
    write({ ...cur, installed: true, showAdvanced: true });
  }
}

/**
 * Are we in the new-player "forgiving" window? True iff the player has won
 * fewer than 3 puzzles. Used for: free hints, no game-over, smaller mistake
 * display.
 */
export function isForgivingWindow(): boolean {
  return read().winCount < 3;
}

/**
 * Should advanced surfaces (hard mode, custom puzzle builder, advanced replay
 * scrubber) be visible? True iff:
 *   - the player has explicitly toggled it on, OR
 *   - they've won >= 5 puzzles, OR
 *   - they're an existing pre-v0.5 player (inheritExistingInstall ran)
 */
export function isAdvancedVisible(): boolean {
  const s = read();
  return s.showAdvanced || s.winCount >= 5;
}

/** Should we show the "want to try harder?" prompt right now? */
export function shouldPromptHarder(): boolean {
  const s = read();
  return s.winCount === 3 && !s.promptedHarder && !s.declinedHarder;
}

/** Reset for testing — not exposed in UI. */
export function _resetProgression(): void {
  try { localStorage.removeItem(KEY); } catch {}
}
