import type { EtchMode, EtchSize } from '../engine';

const KEY = 'bilko_etch_best_v1';
const VERSION = 1;

interface BestRow { ms: number; date: string; }
interface BestBlob { v: 1; rows: Record<string, BestRow>; }

function read(): BestBlob {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return { v: 1, rows: {} };
    const j = JSON.parse(raw);
    if (j.v !== VERSION) return { v: 1, rows: {} };
    return j as BestBlob;
  } catch { return { v: 1, rows: {} }; }
}

function write(b: BestBlob) {
  try { localStorage.setItem(KEY, JSON.stringify(b)); } catch {}
}

function key(mode: EtchMode, size: EtchSize): string { return `${mode}:${size}`; }

export function getBest(mode: EtchMode, size: EtchSize): BestRow | undefined {
  return read().rows[key(mode, size)];
}

export function recordSolve(mode: EtchMode, size: EtchSize, ms: number): boolean {
  const blob = read();
  const k = key(mode, size);
  const cur = blob.rows[k];
  if (cur && cur.ms <= ms) return false;
  blob.rows[k] = { ms, date: new Date().toISOString() };
  write(blob);
  return true;
}
