import { memo } from 'react';
import type { Mark } from '../../engine';

interface Props {
  idx: number;
  row: number; col: number;
  rows: number; cols: number;
  mark: Mark;
  isFocused: boolean;
  isPeerRow: boolean;
  isPeerCol: boolean;
  isPeerHover: boolean;
  rowClueId: string;
  colClueId: string;
  onFocus: () => void;
}

export const Cell = memo(function Cell(p: Props) {
  const major5Right = (p.col + 1) % 5 === 0 && p.col + 1 < p.cols;
  const major5Bottom = (p.row + 1) % 5 === 0 && p.row + 1 < p.rows;
  const left = p.col === 0;
  const top = p.row === 0;

  const labelMark =
    p.mark === 'fill'  ? 'filled' :
    p.mark === 'cross' ? 'crossed' :
    'empty';

  return (
    <button
      type="button"
      role="gridcell"
      aria-rowindex={p.row + 1}
      aria-colindex={p.col + 1}
      aria-label={`Row ${p.row + 1}, column ${p.col + 1}, ${labelMark}`}
      aria-describedby={`${p.rowClueId} ${p.colClueId}`}
      tabIndex={p.isFocused ? 0 : -1}
      data-cell-idx={p.idx}
      data-mark={p.mark}
      data-focus={p.isFocused || undefined}
      data-peer-row={p.isPeerRow || undefined}
      data-peer-col={p.isPeerCol || undefined}
      data-peer-hover={p.isPeerHover || undefined}
      data-major-r={major5Right || undefined}
      data-major-b={major5Bottom || undefined}
      data-edge-l={left || undefined}
      data-edge-t={top || undefined}
      className="etch-cell"
      onFocus={p.onFocus}
    />
  );
});
