import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { initBusBridge } from './state/bus-bridge';
import { initHintBridge } from './components/hints';
import { useStore, initMultiTabBridge } from './state/store';
import { getMistakeMode } from './features/theme/theme';
import { bootCustomize } from './features/customize/customize';
import { initPrefetch } from './features/perf/prefetch';
import { initInstallPrompt } from './features/pwa/install';
import { applyFriendlyDefaultsOnce } from './features/onboarding/friendly-defaults';
import { inheritExistingInstall, isAdvancedVisible } from './state/progression';
import { installDiagnostics, setDiagnosticsVersion } from './state/diagnostics';

// Friendly defaults (sound/haptics OFF for new players) — must run BEFORE
// feedback init so it picks up the persisted values. Also inherit progression
// state from prior versions so existing players don't see the onboarding CTA.
inheritExistingInstall();
applyFriendlyDefaultsOnce();

// Apply advanced-visibility attribute on the document root so CSS can hide
// power-user surfaces (custom builder, hard-mode, advanced replay) until
// the player either opts in or wins 5 puzzles.
document.documentElement.dataset.advanced = isAdvancedVisible() ? 'shown' : 'hidden';

initBusBridge();
initHintBridge();
bootCustomize();
initPrefetch();
initInstallPrompt();
initMultiTabBridge();

// Restore persisted game (resume from localStorage; runs the migration ladder).
useStore.getState().actions.resume();

// Dev-only state diagnostics: window.__etch_state()
setDiagnosticsVersion('0.6.0');
installDiagnostics();

// Apply persisted mistake mode on boot
const mm = getMistakeMode();
useStore.setState({ mistakeLimit: mm === 'off' ? null : Number(mm) });

// Expose store + bus for Playwright tests in dev mode
if (import.meta.env.DEV) {
  (window as unknown as Record<string, unknown>).__ETCH_STORE__ = useStore;
  import('./lib/bus').then(m => {
    (window as unknown as Record<string, unknown>).__ETCH_BUS__ = m.bus;
  });
}

createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);

// Register PWA service worker (production only — dev would 404 on /sw.js).
if (!import.meta.env.DEV && 'serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    // Use base-relative URL so scope is /projects/etch/ as required by host contract.
    navigator.serviceWorker
      .register('./sw.js', { scope: './' })
      .catch((err: unknown) => console.warn('Etch: sw registration failed', err));
  });
}
