import { bus } from '../../lib/bus';
import { haptics } from './haptics';
import { sound } from './sound';
import { useStore } from '../../state/store';

export { haptics, setHapticsEnabled, isHapticsEnabled } from './haptics';
export { sound, setSoundsEnabled, isSoundsEnabled } from './sound';

let inited = false;

export function initFeedback() {
  if (inited) return;
  inited = true;

  bus.on('cellMarked', ({ kind }) => {
    if (kind === 'fill') { haptics.tap(); sound.mark(); }
    else if (kind === 'cross') { haptics.tick(); sound.cross(); }
    else { /* clear — no feedback */ }
  });

  bus.on('unitCompleted', () => sound.clueComplete());
  bus.on('puzzleSolved', () => { haptics.success(); sound.win(); });
  bus.on('puzzleRevealed', () => sound.reveal());

  let prevMistakes = useStore.getState().mistakes;
  let prevSoftFailed = useStore.getState().softFailed;

  useStore.subscribe(s => {
    if (s.mistakes > prevMistakes && s.mistakeLimit !== null) {
      haptics.bump();
      sound.error();
    }
    if (!prevSoftFailed && s.softFailed) {
      haptics.error();
      sound.error();
    }
    prevMistakes = s.mistakes;
    prevSoftFailed = s.softFailed;
  });
}
