import { lazy, Suspense, useEffect, useState } from 'react';
import { useGameState } from '../state/store';
import { getProgression } from '../state/progression';
import { OnboardingCTA } from '../features/onboarding/OnboardingCTA';

// Lazy-load the picker — the player hits it once per session at most.
// While the chunk loads, render a skeleton with matching layout.
const NewGameSheet = lazy(() => import('../components/mode').then(m => ({ default: m.NewGameSheet })));

function Skeleton() {
  return (
    <div className="etch-newgame-skeleton" role="presentation" aria-hidden="true" data-testid="picker-skeleton">
      <div className="etch-newgame-card">
        <div className="etch-skel-line" style={{ width: '40%', height: 18 }} />
        <div className="etch-skel-line" style={{ width: '60%', height: 10 }} />
        <div style={{ marginTop: 16, marginBottom: 16 }}>
          <span className="etch-skel-pill" />
          <span className="etch-skel-pill" />
        </div>
        <div className="etch-skel-grid">
          {Array.from({ length: 5 }, (_, i) => <span key={i} className="etch-skel-card" />)}
        </div>
        <div className="etch-skel-line" style={{ marginTop: 16, height: 40, borderRadius: 12 }} />
      </div>
    </div>
  );
}

/**
 * Mode slot. Three states:
 *   1. Brand-new player (no progression record, hasn't started intro) → big
 *      one-tap onboarding CTA.
 *   2. New player but already pressed "or pick a different puzzle" → render
 *      the regular picker.
 *   3. Existing/returning player → regular picker.
 *
 * Once a game is in progress (gameStartCount > 0), this slot renders nothing.
 */
export function ModeSlot() {
  const s = useGameState();
  // Decide initial mode synchronously on mount so we don't flash a picker for
  // brand-new players. (`getProgression()` reads localStorage once — O(1).)
  const [pickerRequested, setPickerRequested] = useState(false);
  const [progression, setProgressionState] = useState(() => getProgression());

  // Re-read progression any time gameStartCount returns to 0 (after restart).
  useEffect(() => {
    if (s.gameStartCount === 0) setProgressionState(getProgression());
  }, [s.gameStartCount]);

  if (s.gameStartCount > 0) return null;

  const showOnboarding =
    !pickerRequested &&
    !progression.installed &&
    progression.winCount === 0;

  if (showOnboarding) {
    return <OnboardingCTA onPickerRequested={() => setPickerRequested(true)} />;
  }

  return (
    <Suspense fallback={<Skeleton />}>
      <NewGameSheet />
    </Suspense>
  );
}
