/**
 * One-shot friendly-defaults migration.
 *
 * On first-ever boot (no progression record yet), set sane defaults that
 * minimize friction for a non-gamer adult:
 *   - sound OFF
 *   - haptics OFF (keeps mobile quiet)
 *   - theme: system
 *   - mistake mode (hard mode) OFF
 *   - reduced-motion: respect OS pref (no manual override)
 *
 * For existing players (we detect them via `inheritExistingInstall`), we leave
 * their preferences untouched. The function is idempotent: it checks a one-shot
 * flag and bails out after running once.
 *
 * Time complexity: O(1).
 */
const FLAG = 'bilko_etch_friendly_defaults_v1';

export function applyFriendlyDefaultsOnce(): void {
  try {
    if (localStorage.getItem(FLAG) === '1') return;

    // Only apply defaults if NO prior preferences exist. (`installed=true` in
    // progression means we already inherited from a prior version.)
    const hasPrior =
      localStorage.getItem('bilko_etch_sounds_v1') ||
      localStorage.getItem('bilko_etch_haptics_v1') ||
      localStorage.getItem('bilko_etch_theme_v1') ||
      localStorage.getItem('bilko_etch_mistake_v1') ||
      localStorage.getItem('etch_seen_tutorial') === '1';

    if (!hasPrior) {
      // Sound + haptics OFF (write the explicit "0" so it's clear they were
      // set, not just defaulted).
      localStorage.setItem('bilko_etch_sounds_v1', '0');
      localStorage.setItem('bilko_etch_haptics_v1', '0');
      // Hard-mode OFF — no mistake limit on free play.
      localStorage.removeItem('bilko_etch_mistake_v1');
    }

    localStorage.setItem(FLAG, '1');
  } catch { /* private mode etc. */ }
}
