import { createBus } from 'host-kit';

export type EtchSize = 'sketch' | 'beginner' | 'intermediate' | 'tall' | 'expert';
export type EtchMode = 'daily' | 'free';
export type CellMark = 'fill' | 'cross' | 'clear';

export type EtchEvents = {
  cellMarked: { row: number; col: number; kind: CellMark };
  cellDragStart: { row: number; col: number };
  cellDragEnd: { row: number; col: number };
  modeToggled: { primary: 'fill' | 'cross' };
  hintRequested: { level: 1 | 2 | 3 };
  newGame: { mode: EtchMode; size: EtchSize };
  puzzleSolved: {
    mode: EtchMode; size: EtchSize;
    timeMs: number; mistakes: number; hintsUsed: number;
    isPersonalBest: boolean;
  };
  puzzleRevealed: { mode: EtchMode; size: EtchSize };
  unitCompleted: { kind: 'row' | 'col'; index: number };
  themeChanged: { mode: 'light' | 'dark' | 'sepia' | 'system'; cb: boolean; hc: boolean };
  achievementUnlocked: { id: string; label: string; desc: string };
  movePlayed: { kind: 'mark' | 'drag' | 'undo' | 'redo'; t: number };
  /** Onboarding/nudge events */
  nudgeFreeHint: { reason: 'mistakes' | 'stuck' | 'easier' };
  /** Toggled by Settings — listeners refresh advanced-only UI */
  advancedVisibilityChanged: { visible: boolean };
  /** Persisted save was unreadable — emit once so the UI shows a recovery toast. */
  saveReset: { reason: 'json' | 'schema' | 'migrate' };
  /** Another tab took ownership of the same run. UI offers a re-sync. */
  multiTabConflict: { otherWriterId: string; otherRev: number; iso: string };
}

export const bus = createBus<EtchEvents>();
