import { useEffect, useState } from 'react';
import { bus } from '../../lib/bus';
import { readPendingSaveReset, acknowledgeSaveReset } from '../../state/store';
import './error.css';

/**
 * One-shot recovery toast shown when the persisted run blob can't be
 * loaded (bad JSON, schema mismatch, failed migration). The save has
 * already been wiped at this point — the toast tells the player and
 * gives them a single "Got it" button.
 *
 * The toast is `role="alert"` so screen readers announce it, but the
 * accessible name is concise: "Couldn't restore your last puzzle —
 * starting fresh." No keyboard trap; the close button is the only
 * interactive element.
 *
 * Time complexity: O(1) per render.
 */
export function SaveResetToast() {
  // `readPendingSaveReset()` is non-destructive — safe across StrictMode
  // double-mount. The reason gets cleared only when the user dismisses.
  const [reason, setReason] = useState<string | null>(() => readPendingSaveReset());
  useEffect(() => {
    if (!reason) {
      const r = readPendingSaveReset();
      if (r) setReason(r);
    }
    const off = bus.on('saveReset', ({ reason: rr }) => setReason(rr));
    return off;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  if (!reason) return null;
  return (
    <div
      className="etch-save-toast"
      role="alert"
      aria-live="assertive"
      data-testid="save-reset-toast"
    >
      <div className="etch-save-toast-body">
        <strong>Couldn’t restore your last puzzle.</strong>
        <span>Starting fresh — your stats and streak are safe.</span>
      </div>
      <button
        type="button"
        className="etch-save-toast-close"
        aria-label="Dismiss save recovery notice"
        onClick={() => { acknowledgeSaveReset(); setReason(null); }}
      >Got it</button>
    </div>
  );
}
