import { useState } from 'react';
import { useGameState } from '../../state/store';
import { getStreak } from '../../state/streak-store';
import { dateToIso } from '../../engine';
import { buildShareTile } from './share-format';

export function ShareTile({ onClose }: { onClose: () => void }) {
  const s = useGameState();
  const [copied, setCopied] = useState(false);
  const today = new Date();
  const iso = dateToIso(today);
  const streak = getStreak();
  const text = buildShareTile({
    solution: s.board.solution,
    rows: s.board.rows, cols: s.board.cols,
    size: s.size, mode: s.mode,
    date: today, timeMs: s.timeMs,
    mistakes: s.mistakes, hintsUsed: s.hintsUsed,
    streak: streak.current, iso,
  });

  async function share() {
    if (navigator.share) {
      try { await navigator.share({ text }); onClose(); return; } catch {}
    }
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => onClose(), 1500);
    } catch {}
  }

  return (
    <div className="etch-share-backdrop" role="dialog" aria-modal="true" onClick={onClose}>
      <div className="etch-share-sheet" onClick={(e) => e.stopPropagation()}>
        <header>
          <h2>Share your Etch</h2>
          <button onClick={onClose} aria-label="Close">×</button>
        </header>
        <pre className="etch-share-tile">{text}</pre>
        <button className="etch-share-go" onClick={() => void share()}>
          {copied ? 'Copied!' : 'Share / Copy'}
        </button>
      </div>
    </div>
  );
}
