import { lazy, Suspense, useEffect, useRef, useReducer, useState } from 'react';
import {
  getTheme, setTheme, getColorBlind, setColorBlind, getHighContrast, setHighContrast,
  getMistakeMode, setMistakeMode, type ThemeChoice, type MistakeMode,
} from './theme';
import { useStore } from '../../state/store';
import { bus } from '../../lib/bus';
import './theme.css';

const StatsSheet = lazy(() => import('../stats/StatsSheet'));
const SettingsSheet = lazy(() => import('../settings/SettingsSheet'));

export function ThemeMenu() {
  const [open, setOpen] = useState(false);
  const [statsOpen, setStatsOpen] = useState(false);
  const [settingsOpen, setSettingsOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);
  const btnRef = useRef<HTMLButtonElement>(null);
  const [, force] = useReducer(x => x + 1, 0);

  // Close on outside click
  useEffect(() => {
    if (!open) return;
    function offClick(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    }
    document.addEventListener('mousedown', offClick);
    return () => document.removeEventListener('mousedown', offClick);
  }, [open]);

  // Close on Escape, restore focus to button
  useEffect(() => {
    if (!open) return;
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') { setOpen(false); btnRef.current?.focus(); }
    }
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [open]);

  function pickTheme(c: ThemeChoice) {
    setTheme(c); force();
    bus.emit('themeChanged', { mode: c, cb: getColorBlind(), hc: getHighContrast() });
  }
  function toggleCb() {
    setColorBlind(!getColorBlind()); force();
    bus.emit('themeChanged', { mode: getTheme(), cb: getColorBlind(), hc: getHighContrast() });
  }
  function toggleHc() {
    setHighContrast(!getHighContrast()); force();
    bus.emit('themeChanged', { mode: getTheme(), cb: getColorBlind(), hc: getHighContrast() });
  }
  function pickMistake(m: MistakeMode) {
    setMistakeMode(m); force();
    useStore.setState({ mistakeLimit: m === 'off' ? null : Number(m) });
  }

  const t = getTheme();
  const cb = getColorBlind();
  const hc = getHighContrast();
  const mm = getMistakeMode();

  return (
    <div className="etch-theme-menu" ref={ref}>
      <button
        ref={btnRef}
        className="etch-theme-btn"
        onClick={() => setOpen(o => !o)}
        aria-label="Theme settings"
        aria-haspopup="dialog"
        aria-expanded={open}
      >
        Aa
      </button>
      {open && (
        <div role="dialog" className="etch-theme-popover" aria-label="Settings">
          <section>
            <h3>Theme</h3>
            {(['light', 'dark', 'sepia', 'system'] as ThemeChoice[]).map(c => (
              <label key={c}>
                <input type="radio" name="theme" checked={c === t} onChange={() => pickTheme(c)} />
                {c.charAt(0).toUpperCase() + c.slice(1)}
              </label>
            ))}
          </section>
          <section>
            <h3>Display</h3>
            <label>
              <input type="checkbox" checked={cb} onChange={toggleCb} />
              Color-blind safe
            </label>
            <label>
              <input type="checkbox" checked={hc} onChange={toggleHc} />
              High contrast
            </label>
          </section>
          <section>
            <h3>Mistake mode</h3>
            {(['off', '3', '5'] as MistakeMode[]).map(m => (
              <label key={m}>
                <input type="radio" name="mistake" checked={m === mm} onChange={() => pickMistake(m)} />
                {m === 'off' ? 'Off (default)' : `${m} strikes`}
              </label>
            ))}
          </section>
          <div data-slot="theme-extras" />
          <section className="etch-theme-links">
            <button
              type="button"
              className="etch-theme-link"
              onClick={() => { setSettingsOpen(true); setOpen(false); }}
            >
              All settings →
            </button>
            <button
              type="button"
              className="etch-theme-link"
              onClick={() => { setStatsOpen(true); setOpen(false); }}
            >
              Your stats →
            </button>
          </section>
        </div>
      )}
      {(statsOpen || settingsOpen) && (
        <Suspense fallback={null}>
          {statsOpen && <StatsSheet onClose={() => setStatsOpen(false)} />}
          {settingsOpen && <SettingsSheet onClose={() => setSettingsOpen(false)} />}
        </Suspense>
      )}
    </div>
  );
}
