/**
 * Lifetime player stats. Tracks aggregate counters across all modes/sizes so the
 * stats screen can show "lifetime puzzles solved", "average mistakes", etc.
 *
 * Storage: localStorage.bilko_etch_stats_v1, ~200 bytes JSON.
 * Time complexity: every helper is O(1) — we keep running totals, never replay
 * a history list.
 */
import type { EtchMode, EtchSize } from '../engine';

const KEY = 'bilko_etch_stats_v1';
const VERSION = 1;

export interface LifetimeStats {
  v: 1;
  puzzlesStarted: number;
  puzzlesSolved: number;
  totalMistakes: number;
  totalHints: number;
  totalTimeMs: number;
  perfectSolves: number; // 0 mistakes, 0 hints
  /** Solves bucketed by size — for the stats grid */
  bySize: Partial<Record<EtchSize, { solved: number; bestMs: number | null }>>;
  /** Solves bucketed by mode — daily vs free */
  byMode: Partial<Record<EtchMode, { solved: number }>>;
}

const empty: LifetimeStats = {
  v: 1,
  puzzlesStarted: 0,
  puzzlesSolved: 0,
  totalMistakes: 0,
  totalHints: 0,
  totalTimeMs: 0,
  perfectSolves: 0,
  bySize: {},
  byMode: {},
};

function read(): LifetimeStats {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return { ...empty, bySize: {}, byMode: {} };
    const j = JSON.parse(raw);
    if (j.v !== VERSION) return { ...empty, bySize: {}, byMode: {} };
    return j as LifetimeStats;
  } catch { return { ...empty, bySize: {}, byMode: {} }; }
}

function write(s: LifetimeStats) {
  try { localStorage.setItem(KEY, JSON.stringify(s)); } catch {}
}

export function getLifetimeStats(): LifetimeStats {
  return read();
}

export function notePuzzleStart(): void {
  const s = read();
  s.puzzlesStarted += 1;
  write(s);
}

export function notePuzzleSolved(opts: {
  mode: EtchMode;
  size: EtchSize;
  timeMs: number;
  mistakes: number;
  hintsUsed: number;
}): LifetimeStats {
  const s = read();
  s.puzzlesSolved += 1;
  s.totalMistakes += opts.mistakes;
  s.totalHints += opts.hintsUsed;
  s.totalTimeMs += opts.timeMs;
  if (opts.mistakes === 0 && opts.hintsUsed === 0) s.perfectSolves += 1;

  const bs = s.bySize[opts.size] ?? { solved: 0, bestMs: null };
  bs.solved += 1;
  if (bs.bestMs === null || opts.timeMs < bs.bestMs) bs.bestMs = opts.timeMs;
  s.bySize[opts.size] = bs;

  const bm = s.byMode[opts.mode] ?? { solved: 0 };
  bm.solved += 1;
  s.byMode[opts.mode] = bm;

  write(s);
  return s;
}

export function resetLifetimeStats(): void {
  try { localStorage.removeItem(KEY); } catch {}
}

export function avgMistakes(s: LifetimeStats): number {
  if (s.puzzlesSolved === 0) return 0;
  return s.totalMistakes / s.puzzlesSolved;
}

export function avgTimeMs(s: LifetimeStats): number {
  if (s.puzzlesSolved === 0) return 0;
  return s.totalTimeMs / s.puzzlesSolved;
}
