import type { Board, Mark } from './types';
import { freezeBoard } from './board';

export function isWon(b: Board): boolean {
  for (let i = 0; i < b.solution.length; i++) {
    if (b.solution[i] === 1 && b.cells[i] !== 'fill') return false;
  }
  return true;
}

export function autoCrossOnWin(b: Board): Board {
  if (!isWon(b)) return b;
  const cells = b.cells.slice() as Mark[];
  for (let i = 0; i < b.solution.length; i++) {
    if (b.solution[i] === 0 && cells[i] === 'unmarked') cells[i] = 'cross';
  }
  return freezeBoard({ ...b, cells });
}

export function countMistakes(b: Board): number {
  let n = 0;
  for (let i = 0; i < b.solution.length; i++) {
    if (b.cells[i] === 'fill' && b.solution[i] === 0) n++;
  }
  return n;
}
