import { useEffect, useState } from 'react';
import { useGameActions } from '../../state/store';
import { dailyDifficulty } from '../../engine';
import './welcome.css';

const KEY = 'bilko_etch_last_visit_v1';
const SESSION_FLAG = 'bilko_etch_welcome_seen_session';
const TWO_DAYS_MS = 2 * 86_400_000;

function readLast(): number | null {
  try { const v = localStorage.getItem(KEY); return v ? Number(v) : null; } catch { return null; }
}
function writeNow(): void {
  try { localStorage.setItem(KEY, String(Date.now())); } catch {}
}
function sessionDismissed(): boolean {
  try { return sessionStorage.getItem(SESSION_FLAG) === '1'; } catch { return false; }
}
function markDismissed(): void {
  try { sessionStorage.setItem(SESSION_FLAG, '1'); } catch {}
}

/**
 * "Welcome back" banner — shown on first load of a session when the previous
 * visit was more than two days ago. Provides a one-tap CTA for the daily; the
 * X dismisses for the rest of the session.
 *
 * Suppressed when:
 *  - user hasn't visited before (no nag for new users — they get the tutorial)
 *  - last visit was <= 2 days ago
 *  - they've dismissed it in this tab already
 */
export function WelcomeBack() {
  const a = useGameActions();
  const [show, setShow] = useState(false);

  useEffect(() => {
    const last = readLast();
    writeNow();
    if (last == null) return; // first-ever visit — fall through to tutorial
    if (sessionDismissed()) return;
    if (Date.now() - last > TWO_DAYS_MS) setShow(true);
  }, []);

  if (!show) return null;
  const today = dailyDifficulty(new Date());

  function dismiss() { markDismissed(); setShow(false); }
  async function startDaily() {
    dismiss();
    try { await a.newGame({ mode: 'daily' }); } catch { /* swallow — main UI handles errors */ }
  }

  return (
    <div className="etch-welcome" role="status" data-testid="welcome-back">
      <div className="etch-welcome-text">
        <strong>Welcome back!</strong>
        <span>Today's daily is <em style={{ textTransform: 'capitalize' }}>{today}</em>.</span>
      </div>
      <div className="etch-welcome-actions">
        <button type="button" className="etch-welcome-cta" onClick={() => void startDaily()}>
          Play daily
        </button>
        <button
          type="button"
          className="etch-welcome-close"
          aria-label="Dismiss welcome message"
          onClick={dismiss}
        >
          ×
        </button>
      </div>
    </div>
  );
}
