/**
 * Formal state machine for the Etch run lifecycle.
 *
 *      menu ───start──> playing ──pause──> paused
 *                          │                  │
 *                          │  win              │ resume
 *                          ▼                  │
 *                         won <───┐           │
 *                          ▲      │ rematch   │
 *                          │      │           │
 *                       lose       └────── playing
 *                          ▼
 *                         lost ──quit──> menu
 *
 * `error` is a terminal-ish state any of the live states can fall into when
 * the migration layer rejects a save. The recovery path is `error → menu`
 * via the same `quit` transition. The dev-only `assertTransition` throws on
 * any combo not listed in TRANSITIONS; production replaces it with a no-op
 * so we keep zero runtime cost.
 *
 * Time complexity: every assertion is O(1) — set lookup on a small set.
 */
import type { EtchSize, EtchMode } from '../engine';

export type EtchState =
  | 'menu'      // picker is up, no run in flight
  | 'playing'   // run in progress
  | 'paused'    // run in progress, time frozen
  | 'won'       // run finished successfully
  | 'lost'      // run finished by exceeding mistake limit
  | 'error';    // unrecoverable boot/runtime issue; fall back to clean state

export type EtchTransition =
  | 'start'      // menu -> playing
  | 'pause'      // playing -> paused
  | 'resume'     // paused -> playing
  | 'win'        // playing -> won
  | 'lose'       // playing -> lost
  | 'quit'       // any -> menu (user explicitly back-to-menu)
  | 'reveal'     // playing -> won (treat reveal as 'win-ish' end state for UX)
  | 'rematch'    // won|lost -> playing (restart same puzzle)
  | 'newGame'    // menu|won|lost|playing|paused -> playing (start a fresh puzzle; allowed during a run)
  | 'fail'       // any -> error (parse/migration failure)
  | 'recover';   // error -> menu (after toast acked)

/**
 * Adjacency list of allowed (state -> transition -> nextState) edges.
 * Anything not listed here will trip the dev assertion.
 *
 * The set is deliberately permissive on `newGame` because the player can
 * always pick "Today's puzzle" from the top bar mid-run; we don't penalise
 * that with a fail. The current run is silently abandoned.
 */
export const TRANSITIONS: Record<EtchState, Partial<Record<EtchTransition, EtchState>>> = {
  menu: {
    start: 'playing',
    newGame: 'playing',
    fail: 'error',
  },
  playing: {
    pause: 'paused',
    win: 'won',
    lose: 'lost',
    reveal: 'won',
    quit: 'menu',
    newGame: 'playing',
    fail: 'error',
  },
  paused: {
    resume: 'playing',
    quit: 'menu',
    newGame: 'playing',
    fail: 'error',
  },
  won: {
    rematch: 'playing',
    newGame: 'playing',
    quit: 'menu',
    fail: 'error',
  },
  lost: {
    rematch: 'playing',
    newGame: 'playing',
    quit: 'menu',
    fail: 'error',
  },
  error: {
    recover: 'menu',
    quit: 'menu',
  },
};

export interface TransitionEvent {
  from: EtchState;
  to: EtchState;
  via: EtchTransition;
  t: number;
  /** Optional snapshot context (mode/size at the time). Helpful in dumps. */
  ctx?: { mode?: EtchMode; size?: EtchSize };
}

const HISTORY_CAP = 50;

/**
 * Lightweight transition history used by both the dev diagnostics dump and
 * any test that wants to assert "after Q, S, T the machine is in won".
 * Capped at HISTORY_CAP entries — older transitions evicted from the front
 * (O(1) amortized — `shift()` on a small ring is fine here, never a hot path).
 */
class Machine {
  private _state: EtchState = 'menu';
  private _history: TransitionEvent[] = [];

  get state(): EtchState { return this._state; }
  get history(): ReadonlyArray<TransitionEvent> { return this._history; }

  /**
   * Apply a transition. In dev, throws if the edge isn't in `TRANSITIONS`.
   * In production, the same call returns `false` and the caller can ignore.
   *
   * Time complexity: O(1).
   */
  apply(via: EtchTransition, ctx?: TransitionEvent['ctx']): boolean {
    const allowed = TRANSITIONS[this._state];
    const next = allowed[via];
    if (!next) {
      if (typeof import.meta !== 'undefined' && import.meta.env?.DEV) {
        throw new Error(`Etch FSM: illegal transition ${this._state} --${via}--> ?`);
      }
      return false;
    }
    const ev: TransitionEvent = { from: this._state, to: next, via, t: Date.now(), ctx };
    this._state = next;
    this._history.push(ev);
    if (this._history.length > HISTORY_CAP) this._history.shift();
    return true;
  }

  /** Force the machine into a state without recording a transition. Used at
   *  boot when we hydrate from a save (the save itself encodes the resting state).
   *  Time complexity: O(1). */
  force(state: EtchState): void {
    this._state = state;
  }

  /** Reset for tests. */
  reset(): void {
    this._state = 'menu';
    this._history = [];
  }
}

export const fsm = new Machine();

/** Returns true if (from --via--> ?) is a legal edge. Pure helper. */
export function canTransition(from: EtchState, via: EtchTransition): boolean {
  return !!TRANSITIONS[from]?.[via];
}
