import { RowClues, ColClues } from '../components/clues';
import { useGameState } from '../state/store';
import '../components/clues/clues.css';

export function CluesSlot() {
  const { board } = useGameState();
  if (board.cells.length === 0) return null;
  return (
    <>
      <ColClues />
      <RowClues />
    </>
  );
}
