import { type ReactNode, lazy, Suspense, useEffect, useState } from 'react';
import { Tutorial, hasSeenTutorial } from '../tutorial';
import { ErrorBoundary } from '../../features/error/ErrorBoundary';
import { getProgression } from '../../state/progression';
import './shell.css';

const HelpSheet = lazy(() => import('../../features/help/HelpSheet'));
const WhatsNewSheet = lazy(() => import('../../features/whatsnew/WhatsNewSheet'));

const WHATS_NEW_KEY = 'bilko_etch_seen_whatsnew_v0_5';

function hasSeenWhatsNew(): boolean {
  try { return localStorage.getItem(WHATS_NEW_KEY) === '1'; } catch { return false; }
}
function markWhatsNewSeen(): void {
  try { localStorage.setItem(WHATS_NEW_KEY, '1'); } catch {}
}

interface AppShellProps {
  children: ReactNode;
  /** Renders into the top bar's right-hand action slot (theme button etc.) */
  topBarExtras?: ReactNode;
}

/**
 * Thin-chrome shell for Etch.
 *
 * The "?" button in the top bar opens the tutorial. The global "?" keystroke
 * opens the help sheet (keyboard cheatsheet + nonogram techniques). The
 * "What's new" indicator surfaces v0.4.0 changes on first run after upgrading.
 */
export function AppShell({ children, topBarExtras }: AppShellProps) {
  // For brand-new players the OnboardingCTA replaces the auto-tutorial — they
  // learn by playing the 5x5 intro. Returning players who haven't seen the
  // tutorial still get it. Detection: if progression says "not installed" and
  // winCount === 0, the OnboardingCTA is showing — skip the tutorial.
  const [tutorialOpen, setTutorialOpen] = useState<boolean>(() => {
    if (hasSeenTutorial()) return false;
    const p = getProgression();
    const isBrandNew = !p.installed && p.winCount === 0;
    return !isBrandNew;
  });
  const [helpOpen, setHelpOpen] = useState(false);
  // Only auto-show "what's new" to returning users who've seen the tutorial.
  const [whatsNewOpen, setWhatsNewOpen] = useState<boolean>(() => {
    return hasSeenTutorial() && !hasSeenWhatsNew();
  });

  // Global "?" shortcut for help (skip when typing into inputs / when another
  // dialog is already open). Match both `e.key === '?'` (most browsers) and
  // shift+/ via `e.code` (covers Playwright-style raw key emulation).
  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      const isQuestion = e.key === '?' || (e.code === 'Slash' && e.shiftKey);
      if (!isQuestion) return;
      const t = e.target as HTMLElement | null;
      if (t && (t.tagName === 'INPUT' || t.tagName === 'TEXTAREA' || t.isContentEditable)) return;
      if (document.querySelector('[role="dialog"][aria-modal="true"]')) return;
      e.preventDefault();
      setHelpOpen(true);
    }
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, []);

  function closeWhatsNew() { markWhatsNewSeen(); setWhatsNewOpen(false); }

  return (
    <div className="etch-shell">
      <header className="etch-topbar" role="banner">
        <div className="etch-topbar-left">
          <span className="etch-brand-eyebrow">Bilko</span>
          <span className="etch-brand-sep" aria-hidden="true">·</span>
          <h1 className="etch-brand-title">Etch</h1>
        </div>
        <div className="etch-topbar-right">
          {topBarExtras}
          <button
            type="button"
            className="etch-help-btn"
            aria-label="How to play"
            title="How to play"
            onClick={() => setTutorialOpen(true)}
          >
            ?
          </button>
        </div>
      </header>
      <main className="etch-main" id="main">
        <ErrorBoundary>{children}</ErrorBoundary>
      </main>
      <footer className="etch-footer">
        <a href="https://bilko.run" className="etch-footer-link">bilko.run</a>
      </footer>
      {tutorialOpen && <Tutorial onClose={() => setTutorialOpen(false)} />}
      {(helpOpen || whatsNewOpen) && (
        <Suspense fallback={null}>
          {helpOpen && <HelpSheet onClose={() => setHelpOpen(false)} />}
          {whatsNewOpen && <WhatsNewSheet onClose={closeWhatsNew} />}
        </Suspense>
      )}
    </div>
  );
}
