import './tutorial.css';

export type TileMark = 'u' | 'fill' | 'cross'; // 'u' = unmarked

interface TutorialBoardProps {
  rows: number[][];
  cols: number[][];
  marks: TileMark[];   // length = rows.length * cols.length
  highlight?: 'rowClue' | 'colClue' | 'fill' | 'cross';
}

/**
 * Static, non-interactive nonogram preview used only inside the tutorial.
 *
 * Visual language deliberately matches the real game: same paper / ink /
 * cross-mark tokens, same major-grid borders every 5 cells, same clue digit
 * layout. We render it inert (role="img") so screen readers ignore the
 * decorative grid and read the descriptive caption instead.
 */
export function TutorialBoard({ rows, cols, marks, highlight }: TutorialBoardProps) {
  const nRows = rows.length;
  const nCols = cols.length;

  // For the demo grids we always use a 5x5 plus puzzle, so highlight the
  // middle row clue (the "5") and the middle row of cells.
  const highlightRow = 2;
  const highlightCol = 2;

  return (
    <div
      className="etch-tut-grid"
      role="img"
      aria-label="Nonogram demonstration"
      style={{
        gridTemplateColumns: `auto repeat(${nCols}, 1fr)`,
        gridTemplateRows: `auto repeat(${nRows}, 1fr)`,
      }}
    >
      {/* top-left corner spacer */}
      <div className="etch-tut-corner" aria-hidden="true" />
      {/* column clues */}
      {cols.map((cl, c) => (
        <div
          key={`c${c}`}
          className="etch-tut-col-clue"
          data-highlight={highlight === 'colClue' && c === highlightCol ? '' : undefined}
        >
          {cl.map((n, i) => <span key={i}>{n}</span>)}
        </div>
      ))}
      {/* rows: row clue + cells */}
      {rows.map((rl, r) => (
        <div key={`row-${r}`} className="etch-tut-row-wrap" style={{ display: 'contents' }}>
          <div
            className="etch-tut-row-clue"
            data-highlight={highlight === 'rowClue' && r === highlightRow ? '' : undefined}
          >
            {rl.map((n, i) => <span key={i}>{n}</span>)}
          </div>
          {Array.from({ length: nCols }, (_, c) => {
            const idx = r * nCols + c;
            const m = marks[idx] ?? 'u';
            const isMajorR = (c + 1) % 5 === 0 && c + 1 < nCols;
            const isMajorB = (r + 1) % 5 === 0 && r + 1 < nRows;
            const pulseFill = highlight === 'fill' && m === 'fill' && r === highlightRow;
            const pulseCross = highlight === 'cross' && m === 'cross' && r === 0;
            return (
              <div
                key={c}
                className="etch-tut-cell"
                data-mark={m}
                data-major-r={isMajorR || undefined}
                data-major-b={isMajorB || undefined}
                data-pulse={pulseFill || pulseCross ? '' : undefined}
              />
            );
          })}
        </div>
      ))}
    </div>
  );
}
