import { bus } from '../lib/bus';
import { useStore } from './store';

let bridged = false;

export function initBusBridge() {
  if (bridged) return;
  bridged = true;

  bus.on('cellMarked', ({ row, col, kind }) => {
    useStore.getState().actions.applyMark({ row, col }, kind);
  });

  // Note: no newGame listener here — the store emits 'newGame' after starting a game,
  // so listening here would create an infinite loop.

  bus.on('puzzleSolved', ({ mode }) => {
    if (mode === 'daily') {
      const iso = (window as any).__ETCH_LAST_DAILY_ISO__ ?? new Date().toISOString().slice(0, 10);
      history.replaceState(null, '', `?d=${iso}`);
    }
  });

  // Free-hint nudge → emit `hintRequested` (the same path the hint button takes).
  // Onboarding nudges Issue this when a new player is stuck or mis-clicking,
  // and we explicitly *don't* deduct from any hint quota (the bridge already
  // calls noteHintUsed only on level-3 escalation).
  bus.on('nudgeFreeHint', () => {
    bus.emit('hintRequested', { level: 1 });
  });
}
