import { create } from 'zustand';
import type { HintInfo } from '../engine';

interface HintState {
  level: 0 | 1 | 2 | 3;
  info: HintInfo | null;
  setLevel: (l: 0 | 1 | 2 | 3, info: HintInfo | null) => void;
  reset: () => void;
}

export const useHintStore = create<HintState>(set => ({
  level: 0,
  info: null,
  setLevel: (level, info) => set({ level, info }),
  reset: () => set({ level: 0, info: null }),
}));
