import { useEffect, useState } from 'react';
import { bus } from '../../lib/bus';
import './achievements.css';

interface Toast { id: string; label: string; desc: string; }

/**
 * Small toast stack that pops in when an achievement unlocks. Queued so multiple
 * unlocks at the end of a perfect, fast, first-of-a-kind solve still show one
 * after another (~3.5 s each).
 *
 * In-boot bundle — kept tiny: 50 LOC + 1 KB CSS.
 */
export function AchievementToast() {
  const [queue, setQueue] = useState<Toast[]>([]);
  const [showing, setShowing] = useState<Toast | null>(null);

  useEffect(() => {
    const off = bus.on('achievementUnlocked', ({ id, label, desc }) => {
      setQueue(q => [...q, { id, label, desc }]);
    });
    return off;
  }, []);

  useEffect(() => {
    if (showing || queue.length === 0) return;
    const next = queue[0]!;
    setShowing(next);
    setQueue(q => q.slice(1));
    const t = setTimeout(() => setShowing(null), 3500);
    return () => clearTimeout(t);
  }, [queue, showing]);

  if (!showing) return null;
  return (
    <div
      className="etch-ach-toast"
      role="status"
      aria-live="polite"
      data-testid="achievement-toast"
    >
      <span className="etch-ach-medal" aria-hidden="true">★</span>
      <div className="etch-ach-text">
        <span className="etch-ach-eyebrow">Achievement unlocked</span>
        <span className="etch-ach-label">{showing.label}</span>
        <span className="etch-ach-desc">{showing.desc}</span>
      </div>
    </div>
  );
}
