/**
 * PWA install: capture the deferred prompt event, expose `triggerInstall()` for
 * a UI button to call, and remember whether we've already prompted/dismissed.
 *
 * Constraint (Bilko host contract): the service worker scope is locked to
 * /projects/etch/ — that's enforced in main.tsx and in public/sw.js. The
 * manifest's start_url and scope must match.
 */
const KEY_PROMPTED = 'bilko_etch_install_prompted_v1';

interface BeforeInstallPromptEvent extends Event {
  readonly platforms: string[];
  prompt(): Promise<void>;
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>;
}

let deferred: BeforeInstallPromptEvent | null = null;
let listeners: Array<(available: boolean) => void> = [];

export function initInstallPrompt(): void {
  window.addEventListener('beforeinstallprompt', (e: Event) => {
    e.preventDefault();
    deferred = e as BeforeInstallPromptEvent;
    listeners.forEach(fn => fn(true));
  });
  window.addEventListener('appinstalled', () => {
    deferred = null;
    listeners.forEach(fn => fn(false));
  });
}

export function isInstallAvailable(): boolean { return deferred !== null; }

export function alreadyPrompted(): boolean {
  try { return localStorage.getItem(KEY_PROMPTED) === '1'; } catch { return false; }
}

export function markPrompted(): void {
  try { localStorage.setItem(KEY_PROMPTED, '1'); } catch {}
}

export async function triggerInstall(): Promise<'accepted' | 'dismissed' | 'unavailable'> {
  if (!deferred) return 'unavailable';
  await deferred.prompt();
  const choice = await deferred.userChoice;
  markPrompted();
  deferred = null;
  listeners.forEach(fn => fn(false));
  return choice.outcome;
}

export function onInstallAvailabilityChange(fn: (available: boolean) => void): () => void {
  listeners.push(fn);
  return () => { listeners = listeners.filter(x => x !== fn); };
}
