/**
 * Achievements — earnable medals tied to milestones. Stored in localStorage as
 * a compact set of unlocked ids + an optional unlockedAt timestamp.
 *
 * Time complexity: every helper is O(N) over the medal catalog (N=12). Storage
 * format is a single object keyed by id, ~400 bytes max.
 */
import type { EtchMode, EtchSize } from '../engine';
import { getLifetimeStats } from './lifetime-stats';
import { getStreak } from './streak-store';

export type AchievementId =
  | 'first-solve'
  | 'no-mistakes'
  | 'no-hints'
  | 'flawless'         // 0 mistakes + 0 hints
  | 'streak-3'
  | 'streak-10'
  | 'speed-sketch'     // sketch under 30s
  | 'speed-beginner'   // beginner under 2 min
  | 'speed-expert'     // expert (15x15+) under 5 min
  | 'dailies-7'
  | 'dailies-30'
  | 'all-sizes';       // solved every size at least once

export interface Achievement {
  id: AchievementId;
  label: string;
  desc: string;
}

export const CATALOG: ReadonlyArray<Achievement> = [
  { id: 'first-solve',    label: 'First etch',       desc: 'Solve your first puzzle.' },
  { id: 'no-mistakes',    label: 'Clean hand',       desc: 'Win a puzzle with zero mistakes.' },
  { id: 'no-hints',       label: 'No help needed',   desc: 'Win a puzzle without using any hints.' },
  { id: 'flawless',       label: 'Flawless',         desc: 'Win with zero mistakes AND zero hints.' },
  { id: 'streak-3',       label: '3-day streak',     desc: 'Solve three daily puzzles in a row.' },
  { id: 'streak-10',      label: '10-day streak',    desc: 'Solve ten daily puzzles in a row.' },
  { id: 'speed-sketch',   label: 'Sketch sprinter',  desc: 'Solve a sketch (5×5) in under 30 seconds.' },
  { id: 'speed-beginner', label: 'Quick fingers',    desc: 'Solve a beginner (10×10) in under 2 minutes.' },
  { id: 'speed-expert',   label: 'Big board, fast',  desc: 'Solve a 15×15 or larger in under 5 minutes.' },
  { id: 'dailies-7',      label: 'Week of dailies',  desc: 'Solve 7 daily puzzles in total.' },
  { id: 'dailies-30',     label: 'Month of dailies', desc: 'Solve 30 daily puzzles in total.' },
  { id: 'all-sizes',      label: 'Versatile',        desc: 'Solve every size at least once.' },
];

const KEY = 'bilko_etch_ach_v1';
const VERSION = 1;

interface Blob { v: 1; unlocked: Partial<Record<AchievementId, number>>; }
const empty: Blob = { v: 1, unlocked: {} };

function read(): Blob {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return { ...empty, unlocked: {} };
    const j = JSON.parse(raw);
    if (j.v !== VERSION) return { ...empty, unlocked: {} };
    return j as Blob;
  } catch { return { ...empty, unlocked: {} }; }
}

function write(b: Blob) {
  try { localStorage.setItem(KEY, JSON.stringify(b)); } catch {}
}

export function getUnlocked(): ReadonlyArray<AchievementId> {
  const u = read().unlocked;
  return Object.keys(u) as AchievementId[];
}

export function isUnlocked(id: AchievementId): boolean {
  return read().unlocked[id] != null;
}

export function unlockedAt(id: AchievementId): number | null {
  const t = read().unlocked[id];
  return typeof t === 'number' ? t : null;
}

function unlock(id: AchievementId, now: number, into: AchievementId[]) {
  const b = read();
  if (b.unlocked[id] != null) return;
  b.unlocked[id] = now;
  write(b);
  into.push(id);
}

export interface EvalContext {
  mode: EtchMode;
  size: EtchSize;
  timeMs: number;
  mistakes: number;
  hintsUsed: number;
}

/**
 * Evaluate which achievements just unlocked given the current solve context
 * and the latest lifetime/streak stats. Returns the newly unlocked ids (so the
 * caller can fire a toast). O(catalog) per call, called once per solve.
 *
 * Pure-ish: reads from localStorage and writes back. No DOM access.
 */
export function evaluateOnSolve(ctx: EvalContext): AchievementId[] {
  const now = Date.now();
  const newly: AchievementId[] = [];
  const stats = getLifetimeStats();
  const streak = getStreak();

  if (stats.puzzlesSolved >= 1) unlock('first-solve', now, newly);
  if (ctx.mistakes === 0) unlock('no-mistakes', now, newly);
  if (ctx.hintsUsed === 0) unlock('no-hints', now, newly);
  if (ctx.mistakes === 0 && ctx.hintsUsed === 0) unlock('flawless', now, newly);
  if (streak.current >= 3 || streak.longest >= 3) unlock('streak-3', now, newly);
  if (streak.current >= 10 || streak.longest >= 10) unlock('streak-10', now, newly);
  if (ctx.size === 'sketch' && ctx.timeMs < 30_000) unlock('speed-sketch', now, newly);
  if (ctx.size === 'beginner' && ctx.timeMs < 120_000) unlock('speed-beginner', now, newly);
  // "expert" achievement triggers on any 15+ board, not just the 'expert' size key
  const bigSize = ctx.size === 'intermediate' || ctx.size === 'tall' || ctx.size === 'expert';
  if (bigSize && ctx.timeMs < 300_000) unlock('speed-expert', now, newly);
  const dailySolves = stats.byMode.daily?.solved ?? 0;
  if (dailySolves >= 7)  unlock('dailies-7',  now, newly);
  if (dailySolves >= 30) unlock('dailies-30', now, newly);
  const sizes: EtchSize[] = ['sketch', 'beginner', 'intermediate', 'tall', 'expert'];
  if (sizes.every(s => (stats.bySize[s]?.solved ?? 0) >= 1)) unlock('all-sizes', now, newly);

  return newly;
}

/** Wipe — paired with the existing "reset lifetime stats" affordance. */
export function resetAchievements(): void {
  try { localStorage.removeItem(KEY); } catch {}
}
