import { lazy, Suspense, useEffect, useState } from 'react';
import { bus } from '../lib/bus';
import { RevealOverlay } from '../features/anim/RevealOverlay';
import { initAnim } from '../features/anim';
import { initMistakeFeedback } from '../features/anim/mistake-feedback';
import { initFeedback } from '../features/feedback';
import { mountFeedbackSettings } from '../features/feedback/settings-mount';
import { prefersReducedMotion } from '../features/theme/theme';
import '../features/anim/anim.css';

// Lazy-load the win sheet + confetti so they don't bloat the boot bundle.
const Confetti = lazy(() => import('../features/anim/Confetti').then(m => ({ default: m.Confetti })));
const WinCelebration = lazy(() => import('../features/win/WinCelebration'));

// Init side-effects at module level (stable across renders)
initAnim();
initMistakeFeedback();
initFeedback();
mountFeedbackSettings();

interface WinPayload {
  timeMs: number;
  mistakes: number;
  hintsUsed: number;
  isPersonalBest: boolean;
}

export function AnimationsSlot() {
  const [revealing, setRevealing] = useState(false);
  const [confettiOn, setConfettiOn] = useState(false);
  const [win, setWin] = useState<WinPayload | null>(null);

  useEffect(() => {
    const off = bus.on('puzzleSolved', ({ timeMs, mistakes, hintsUsed, isPersonalBest }) => {
      setRevealing(true);
      // Reveal overlay sets its own attribute and clears it after 940 ms; we just
      // need to unmount the React node soon after so the next solve can re-run it.
      setTimeout(() => setRevealing(false), 940);
      const reduced = prefersReducedMotion();
      // Confetti only for personal-best (signal celebration without overuse).
      if (isPersonalBest && !reduced) {
        setTimeout(() => setConfettiOn(true), 940);
      }
      // Win celebration sheet appears just after the reveal animation completes.
      // Under reduced motion, show it almost immediately.
      const winDelay = reduced ? 120 : 1020;
      setTimeout(() => setWin({ timeMs, mistakes, hintsUsed, isPersonalBest }), winDelay);
    });
    return off;
  }, []);

  return (
    <>
      {revealing && <RevealOverlay />}
      {(confettiOn || win) && (
        <Suspense fallback={null}>
          {confettiOn && <Confetti onDone={() => setConfettiOn(false)} />}
          {win && (
            <WinCelebration
              timeMs={win.timeMs}
              mistakes={win.mistakes}
              hintsUsed={win.hintsUsed}
              isPersonalBest={win.isPersonalBest}
              onClose={() => setWin(null)}
            />
          )}
        </Suspense>
      )}
    </>
  );
}
