import { bus } from '../../lib/bus';
import { useStore } from '../../state/store';
import { initUnitComplete } from './unit-complete';

let inited = false;

export function initAnim() {
  if (inited) return;
  inited = true;

  initUnitComplete();

  bus.on('unitCompleted', ({ kind, index }) => {
    const s = useStore.getState();
    const cells: number[] = [];
    if (kind === 'row') {
      for (let c = 0; c < s.board.cols; c++) cells.push(index * s.board.cols + c);
    } else {
      for (let r = 0; r < s.board.rows; r++) cells.push(r * s.board.cols + index);
    }
    cells.forEach(i => {
      document.querySelector(`[data-cell-idx="${i}"]`)?.setAttribute('data-unit-complete', kind);
    });
    setTimeout(() => {
      cells.forEach(i => {
        document.querySelector(`[data-cell-idx="${i}"]`)?.removeAttribute('data-unit-complete');
      });
    }, 400);
  });

  // Loss flash on soft-fail
  let prevSoftFailed = useStore.getState().softFailed;
  useStore.subscribe(s => {
    if (!prevSoftFailed && s.softFailed) {
      const board = document.querySelector('.etch-board');
      if (board) {
        board.setAttribute('data-loss-flash', 'true');
        setTimeout(() => board.removeAttribute('data-loss-flash'), 300);
      }
    }
    prevSoftFailed = s.softFailed;
  });
}
